//! zed-metrics-sink — aggregates per-layer compression metrics emitted by
//! `live-inference` into a per-layer summary.
//!
//! Replaces the prior stub that synthesized fake metrics from hardcoded
//! model configs. This binary auto-detects the input format by reading
//! the first 4 bytes:
//!   - `BWMR` → bitwise binary (72-byte fixed records, zero-copy parseable)
//!   - `{`    → JSONL (one JSON object per line)
//!
//! Output is the same per-layer summary written as JSONL (one row per
//! layer) plus a human report on stdout. The summary file is JSON for
//! two reasons: (a) the consumer set is tooling/dashboards that prefer
//! JSON, (b) summary rows are sparse — one per layer — so the binary-vs-
//! JSON tradeoff doesn't matter for inter-node throughput.
//!
//! JSONL input rows must deserialize to the same field set as
//! [`MetricsRecord::to_json_line`] (full `MetricsRecord`). Partial rows
//! are rejected so gestalt witnesses match bitwise wire semantics.
//!
//! Usage:
//!   zed-metrics-sink --input PATH --output PATH

use std::collections::BTreeMap;
use std::env;
use std::fs::{File, OpenOptions};
use std::io::{BufReader, Read, Write};

use distributed_inference::metrics_layer_summary::{
    global_gestalt_folds, ingest_binary, ingest_jsonl, LayerAgg,
};
use distributed_inference::standing_wave_metrics_format::MAGIC;

struct Args {
    input: String,
    output: String,
}
fn parse_args() -> Result<Args, String> {
    let argv: Vec<String> = env::args().collect();
    let mut input: Option<String> = None;
    let mut output: Option<String> = None;
    let mut i = 1;
    while i < argv.len() {
        match argv[i].as_str() {
            "--input" => {
                i += 1;
                input = Some(argv.get(i).ok_or("--input needs a value")?.clone());
            }
            "--output" => {
                i += 1;
                output = Some(argv.get(i).ok_or("--output needs a value")?.clone());
            }
            other => return Err(format!("unknown arg: {}", other)),
        }
        i += 1;
    }
    Ok(Args {
        input: input.ok_or("--input is required")?,
        output: output.ok_or("--output is required")?,
    })
}

#[derive(Debug)]
enum InputFormat {
    Binary,
    Json,
    Empty,
}

fn sniff_format(path: &str) -> Result<InputFormat, String> {
    let mut f = File::open(path).map_err(|e| format!("open {}: {}", path, e))?;
    let mut head = [0u8; 4];
    let n = f
        .read(&mut head)
        .map_err(|e| format!("read magic from {}: {}", path, e))?;
    if n == 0 {
        return Ok(InputFormat::Empty);
    }
    if n >= 4 && head == MAGIC {
        return Ok(InputFormat::Binary);
    }
    // JSON line generally starts with '{' (or whitespace then '{'); we accept both.
    if head[0] == b'{' || head[0] == b' ' || head[0] == b'\t' || head[0] == b'\n' {
        return Ok(InputFormat::Json);
    }
    Err(format!(
        "unknown input format at {}: leading bytes {:?} (expected 'BWMR' or '{{')",
        path,
        &head[..n]
    ))
}

fn ingest_binary_file(
    path: &str,
    by_layer: &mut BTreeMap<u32, LayerAgg>,
) -> Result<(usize, usize), String> {
    let mut f = File::open(path).map_err(|e| format!("open binary {}: {}", path, e))?;
    ingest_binary(&mut f, by_layer).map_err(|e| format!("read binary {}: {}", path, e))
}

fn ingest_json_file(
    path: &str,
    by_layer: &mut BTreeMap<u32, LayerAgg>,
) -> Result<(usize, usize), String> {
    let f = File::open(path).map_err(|e| format!("open json {}: {}", path, e))?;
    let reader = BufReader::new(f);
    Ok(ingest_jsonl(reader, by_layer))
}

fn main() -> Result<(), String> {
    let args = parse_args().inspect_err(|_| {
        eprintln!("usage: zed-metrics-sink --input PATH --output PATH");
    })?;

    let fmt = sniff_format(&args.input)?;
    eprintln!("[zed-metrics-sink] input={} format={:?}", args.input, fmt);

    let mut by_layer: BTreeMap<u32, LayerAgg> = BTreeMap::new();
    let (total_rows, bad_rows) = match fmt {
        InputFormat::Binary => ingest_binary_file(&args.input, &mut by_layer)?,
        InputFormat::Json => ingest_json_file(&args.input, &mut by_layer)?,
        InputFormat::Empty => {
            return Err(format!(
                "input file {} is empty. live-inference did not write any \
                 metrics — check stderr for 'no per-layer standing wave \
                 metrics were populated' or knot-load errors.",
                args.input
            ));
        }
    };

    if total_rows == 0 {
        return Err(format!(
            "no parseable rows in {} (bad_rows={}). format={:?}.",
            args.input, bad_rows, fmt
        ));
    }

    let mut out = OpenOptions::new()
        .create(true)
        .write(true)
        .truncate(true)
        .open(&args.output)
        .map_err(|e| format!("open output {}: {}", args.output, e))?;

    let mut all_coverage_sum = 0.0f64;
    let mut all_speedup_sum = 0.0f64;
    let mut all_saved_bytes = 0u64;
    let (global_gestalt_xor_fold, global_gestalt_triad_fold) = global_gestalt_folds(&by_layer);
    for (layer_idx, agg) in &by_layer {
        let mean_coverage = agg.sum_coverage / agg.samples as f64;
        let mean_speedup = agg.sum_speedup / agg.samples as f64;
        all_coverage_sum += mean_coverage;
        all_speedup_sum += mean_speedup;
        all_saved_bytes += agg.sum_saved_bytes;
        let row = format!(
            "{{\"layer_idx\":{},\"samples\":{},\"hidden_dim\":{},\"mean_coverage\":{:.6},\"mean_speedup\":{:.6},\"min_coverage\":{:.6},\"max_coverage\":{:.6},\"sum_saved_bytes\":{},\"gestalt_xor_parity_fold\":{},\"gestalt_triad_mod3_fold\":{}}}\n",
            layer_idx,
            agg.samples,
            agg.hidden_dim,
            mean_coverage,
            mean_speedup,
            agg.min_coverage,
            agg.max_coverage,
            agg.sum_saved_bytes,
            agg.gestalt_xor_parity_fold,
            agg.gestalt_triad_mod3_fold,
        );
        out.write_all(row.as_bytes())
            .map_err(|e| format!("write summary: {}", e))?;
    }
    out.flush().map_err(|e| format!("flush: {}", e))?;

    let n = by_layer.len() as f64;
    println!("============================================================");
    println!(" zed-metrics-sink summary");
    println!("============================================================");
    println!(" Input:             {}  ({:?})", args.input, fmt);
    println!(" Output summary:    {}", args.output);
    println!(" Records parsed:    {}", total_rows);
    println!(" Records skipped:   {}", bad_rows);
    println!(" Layers covered:    {}", by_layer.len());
    if n > 0.0 {
        println!(" Mean coverage:     {:.4}", all_coverage_sum / n);
        println!(
            " Mean speedup:      {:.3}x  (routing, bytes-saved basis)",
            all_speedup_sum / n
        );
    }
    println!(" Total saved bytes: {}", all_saved_bytes);
    println!(
        " Gestalt XOR parity fold (all rows): {}",
        global_gestalt_xor_fold
    );
    println!(
        " Gestalt triad mod3 fold (all rows): {}",
        global_gestalt_triad_fold
    );

    Ok(())
}
